function getParamPoint(t) {
  let a = t * Math.PI * 2 * p;
  let b = (q / p) * a;
  return new THREE.Vector3(
    r * (2 + Math.cos(b)) * 0.5 * Math.cos(a),
    r * (2 + Math.cos(b)) * 0.5 * Math.sin(a),
    r * Math.sin(b) * 0.5
  );
}

